{
  "name": "Lucky Inami Scheme User Panel",
  "description": "A comprehensive real-time responsive dashboard for the Lucky Inami Scheme lottery platform, featuring token purchasing, live draw animations, wallet management, and referral tracking.",
  "requestFramePermissions": [
    "camera",
    "microphone"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum PlanType {
  SILVER = 'SILVER',
  GOLD = 'GOLD',
  PLATINUM = 'PLATINUM'
}

export interface LotteryPlan {
  id: PlanType;
  name: string;
  tokenPrice: number;
  totalTokens: number;
  totalWinners: number;
  prizePerWinner: number;
  drawTime: string;
  colorClass: string;
  bgClass: string;
  icon: string;
}

export interface Token {
  id: number;
  number: number;
  planId: PlanType;
  purchaseDate: string;
  drawDate: string;
  status: 'WAITING' | 'WINNER' | 'NOT_SELECTED';
  prizeAmount?: number;
}

export interface Transaction {
  id: string;
  date: string;
  type: 'DEPOSIT' | 'WITHDRAWAL';
  amount: number;
  charges: number;
  netAmount: number;
  status: 'PENDING' | 'APPROVED' | 'REJECTED';
  method: 'EasyPaisa' | 'JazzCash';
}

export interface User {
  id: string;
  firstName: string;
  lastName: string;
  username: string;
  email: string;
  mobile: string;
  walletBalance: number;
  referralCode: string;
  referralsCount: number;
  activeReferrals: number;
  totalWinnings: number;
}

import React, { useState, useEffect } from 'react';
import { HashRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { UserContext } from './context/UserContext';
import Header from './components/Header';
import Footer from './components/Footer';
import HomePage from './pages/HomePage';
import LotteriesPage from './pages/LotteriesPage';
import TokenPurchasePage from './pages/TokenPurchasePage';
import MyTokensPage from './pages/MyTokensPage';
import WinnersPage from './pages/WinnersPage';
import WalletPage from './pages/WalletPage';
import ReferralPage from './pages/ReferralPage';
import ProfilePage from './pages/ProfilePage';
import LoginPage from './pages/LoginPage';
import SignUpPage from './pages/SignUpPage';
import { MOCK_USER } from './constants';
import { Token, Transaction } from './types';

const App: React.FC = () => {
  const [user, setUser] = useState(MOCK_USER);
  const [isLoggedIn, setIsLoggedIn] = useState(true);
  const [tokens, setTokens] = useState<Token[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([
    {
      id: 'tx_1',
      date: '2024-05-15 10:30 AM',
      type: 'DEPOSIT',
      amount: 1000,
      charges: 100,
      netAmount: 900,
      status: 'APPROVED',
      method: 'EasyPaisa'
    }
  ]);

  const addTokens = (newTokens: Token[]) => {
    setTokens(prev => [...prev, ...newTokens]);
  };

  const updateBalance = (amount: number) => {
    setUser(prev => ({ ...prev, walletBalance: prev.walletBalance + amount }));
  };

  const addTransaction = (tx: Transaction) => {
    setTransactions(prev => [tx, ...prev]);
  };

  return (
    <UserContext.Provider value={{ 
      user, 
      isLoggedIn, 
      tokens, 
      transactions,
      login: () => setIsLoggedIn(true),
      logout: () => setIsLoggedIn(false),
      addTokens,
      updateBalance,
      addTransaction
    }}>
      <Router>
        <div className="flex flex-col min-h-screen">
          {isLoggedIn && <Header />}
          <main className="flex-grow">
            <Routes>
              <Route path="/" element={isLoggedIn ? <HomePage /> : <Navigate to="/login" />} />
              <Route path="/login" element={!isLoggedIn ? <LoginPage /> : <Navigate to="/" />} />
              <Route path="/signup" element={!isLoggedIn ? <SignUpPage /> : <Navigate to="/" />} />
              <Route path="/lotteries" element={<LotteriesPage />} />
              <Route path="/buy/:planId" element={<TokenPurchasePage />} />
              <Route path="/my-tokens" element={<MyTokensPage />} />
              <Route path="/winners" element={<WinnersPage />} />
              <Route path="/wallet" element={<WalletPage />} />
              <Route path="/referral" element={<ReferralPage />} />
              <Route path="/profile" element={<ProfilePage />} />
            </Routes>
          </main>
          {isLoggedIn && <Footer />}
        </div>
      </Router>
    </UserContext.Provider>
  );
};

export default App;

import { createContext, useContext } from 'react';
import { User, Token, Transaction } from '../types';

interface UserContextType {
  user: User;
  isLoggedIn: boolean;
  tokens: Token[];
  transactions: Transaction[];
  login: () => void;
  logout: () => void;
  addTokens: (tokens: Token[]) => void;
  updateBalance: (amount: number) => void;
  addTransaction: (tx: Transaction) => void;
}

export const UserContext = createContext<UserContextType | undefined>(undefined);

export const useUser = () => {
  const context = useContext(UserContext);
  if (!context) throw new Error('useUser must be used within UserProvider');
  return context;
};

import React, { useState } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { Menu, X, Wallet, User as UserIcon, LogOut, Ticket, Trophy, Share2, Home } from 'lucide-react';
import { useUser } from '../context/UserContext';

