  const { user, logout } = useUser();
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const navigate = useNavigate();
  const location = useLocation();

  const navItems = [
    { label: 'Home', path: '/', icon: <Home size={18} /> },
    { label: 'Lotteries', path: '/lotteries', icon: <Ticket size={18} /> },
    { label: 'My Tokens', path: '/my-tokens', icon: <Trophy size={18} /> },
    { label: 'Winners', path: '/winners', icon: <Trophy size={18} /> },
    { label: 'Wallet', path: '/wallet', icon: <Wallet size={18} /> },
    { label: 'Referral', path: '/referral', icon: <Share2 size={18} /> },
    { label: 'Profile', path: '/profile', icon: <UserIcon size={18} /> },
  ];

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  return (
    <header className="sticky top-0 z-50 bg-white border-b border-slate-200 shadow-sm">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between items-center h-16">
          {/* Logo */}
          <Link to="/" className="flex items-center space-x-2">
            <div className="w-10 h-10 bg-indigo-600 rounded-lg flex items-center justify-center text-white font-bold text-xl">
              L
            </div>
            <span className="hidden sm:block font-bold text-lg text-slate-900 tracking-tight">
              Lucky Inami Scheme
            </span>
          </Link>

          {/* Desktop Nav */}
          <nav className="hidden lg:flex space-x-4">
            {navItems.map((item) => (
              <Link
                key={item.path}
                to={item.path}
                className={`flex items-center space-x-1 px-3 py-2 rounded-md text-sm font-medium transition-colors ${
                  location.pathname === item.path
                    ? 'bg-indigo-50 text-indigo-700'
                    : 'text-slate-600 hover:bg-slate-50 hover:text-slate-900'
                }`}
              >
                {item.icon}
                <span>{item.label}</span>
              </Link>
            ))}
          </nav>

          {/* User Section */}
          <div className="flex items-center space-x-4">
            <div className="hidden md:flex flex-col items-end mr-2">
              <span className="text-xs text-slate-500 font-medium">Balance</span>
              <span className="text-sm font-bold text-emerald-600">Rs {user.walletBalance.toLocaleString()}</span>
            </div>

            <button 
              onClick={handleLogout}
              className="p-2 text-slate-500 hover:text-red-600 hover:bg-red-50 rounded-full transition-all"
              title="Logout"
            >
              <LogOut size={20} />
            </button>

            {/* Mobile Menu Toggle */}
            <button
              className="lg:hidden p-2 text-slate-600 hover:bg-slate-100 rounded-md"
              onClick={() => setIsMenuOpen(!isMenuOpen)}
            >
              {isMenuOpen ? <X size={24} /> : <Menu size={24} />}
            </button>
          </div>
        </div>
      </div>

      {/* Mobile Menu */}
      {isMenuOpen && (
        <div className="lg:hidden bg-white border-t border-slate-200 animate-in slide-in-from-top duration-300">
          <div className="px-2 pt-2 pb-3 space-y-1">
            {navItems.map((item) => (
              <Link
                key={item.path}
                to={item.path}
                onClick={() => setIsMenuOpen(false)}
                className={`flex items-center space-x-3 px-3 py-3 rounded-md text-base font-medium ${
                  location.pathname === item.path
                    ? 'bg-indigo-50 text-indigo-700'
                    : 'text-slate-600 hover:bg-slate-50'
                }`}
              >
                {item.icon}
                <span>{item.label}</span>
              </Link>
            ))}
            <div className="mt-4 px-3 py-4 bg-slate-50 rounded-lg flex justify-between items-center">
               <div className="flex flex-col">
                  <span className="text-xs text-slate-500">My Balance</span>
                  <span className="text-lg font-bold text-emerald-600">Rs {user.walletBalance}</span>
               </div>
               <Link to="/wallet" className="bg-indigo-600 text-white px-4 py-2 rounded-lg text-sm font-semibold">
                 Deposit
               </Link>
            </div>
          </div>
        </div>
      )}
    </header>
  );
};

export default Header;

