export default LotteriesPage;

import React, { useState, useMemo } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import { ChevronLeft, Wallet, AlertCircle, CheckCircle2 } from 'lucide-react';
import { LOTTERY_PLANS } from '../constants';
import { useUser } from '../context/UserContext';
import { PlanType, Token } from '../types';

const TokenPurchasePage: React.FC = () => {
  const { planId } = useParams<{ planId: string }>();
  const navigate = useNavigate();
  const { user, updateBalance, addTokens } = useUser();

  const plan = LOTTERY_PLANS.find(p => p.id === planId);
  const [selectedTokens, setSelectedTokens] = useState<number[]>([]);
  const [showSuccess, setShowSuccess] = useState(false);

  // Mocking some sold tokens
  const soldTokens = useMemo(() => [12, 45, 89, 110, 156, 199, 5, 23], []);

  if (!plan) return <div>Plan not found</div>;

  const toggleToken = (num: number) => {
    if (soldTokens.includes(num)) return;
    setSelectedTokens(prev => 
      prev.includes(num) ? prev.filter(t => t !== num) : [...prev, num]
    );
  };

  const totalCost = selectedTokens.length * plan.tokenPrice;
  const canAfford = user.walletBalance >= totalCost;

  const handlePurchase = () => {
    if (!canAfford) return;

    const newTokens: Token[] = selectedTokens.map(num => ({
      id: Math.random(),
      number: num,
      planId: plan.id as PlanType,
      purchaseDate: new Date().toLocaleString(),
      drawDate: 'Next Sunday 4:00 PM',
      status: 'WAITING'
    }));

    updateBalance(-totalCost);
    addTokens(newTokens);
    setShowSuccess(true);

    setTimeout(() => {
      navigate('/my-tokens');
    }, 2000);
  };

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      <Link to="/lotteries" className="inline-flex items-center text-indigo-600 font-semibold mb-6 hover:underline">
        <ChevronLeft size={20} /> Back to Lotteries
      </Link>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Left: Token Grid */}
        <div className="lg:col-span-2">
          <div className="bg-white rounded-3xl p-6 border border-slate-200 shadow-sm">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-xl font-bold text-slate-900">Select Tokens</h2>
              <div className="flex space-x-4 text-xs">
                <div className="flex items-center space-x-1">
                  <div className="w-3 h-3 bg-white border border-slate-200 rounded"></div>
                  <span>Available</span>
                </div>
                <div className="flex items-center space-x-1">
                  <div className="w-3 h-3 bg-indigo-500 rounded"></div>
                  <span>Selected</span>
                </div>
                <div className="flex items-center space-x-1">
                  <div className="w-3 h-3 bg-red-100 text-red-400 rounded flex items-center justify-center text-[8px]">S</div>
                  <span>Sold</span>
                </div>
              </div>
            </div>

            <div className="grid grid-cols-5 sm:grid-cols-10 gap-2">
              {Array.from({ length: 200 }, (_, i) => i + 1).map((num) => {
                const isSold = soldTokens.includes(num);
                const isSelected = selectedTokens.includes(num);
                return (
                  <button
                    key={num}
                    disabled={isSold}
                    onClick={() => toggleToken(num)}
                    className={`h-10 text-xs font-bold rounded-lg transition-all border ${
                      isSold 
                        ? 'bg-red-50 border-red-100 text-red-300 cursor-not-allowed'
                        : isSelected
                          ? 'bg-indigo-600 border-indigo-600 text-white shadow-md transform scale-105'
                          : 'bg-white border-slate-200 text-slate-600 hover:border-indigo-400 hover:bg-slate-50'
                    }`}
                  >
                    {isSold ? 'S' : num}
                  </button>
                );
              })}
            </div>
          </div>
        </div>

        {/* Right: Summary */}
        <div className="lg:col-span-1">
          <div className="sticky top-24 space-y-6">
            <div className="bg-white rounded-3xl p-8 border border-slate-200 shadow-sm">
              <div className={`text-5xl mb-4`}>{plan.icon}</div>
              <h3 className="text-2xl font-bold text-slate-900 mb-2">{plan.name}</h3>
              <p className="text-slate-500 text-sm mb-6">Selected tokens will be entered into the next Sunday draw.</p>

              <div className="space-y-4 border-t border-slate-100 pt-6">
                <div className="flex justify-between text-sm">
                  <span className="text-slate-500">Selected Tokens</span>
                  <span className="font-bold text-slate-900">{selectedTokens.length}</span>
                </div>
                <div className="flex flex-wrap gap-1 max-h-24 overflow-y-auto mt-2">
                  {selectedTokens.map(t => (
                    <span key={t} className="px-2 py-0.5 bg-slate-100 text-slate-700 text-[10px] rounded font-bold">#{t}</span>
                  ))}
                </div>
                <div className="flex justify-between text-sm">
                  <span className="text-slate-500">Price per Token</span>
                  <span className="font-bold text-slate-900">Rs {plan.tokenPrice}</span>
                </div>
                <div className="flex justify-between text-lg pt-4 border-t border-slate-100">
                  <span className="font-bold text-slate-900">Total Amount</span>
                  <span className="font-extrabold text-indigo-600">Rs {totalCost.toLocaleString()}</span>
                </div>
              </div>
            </div>

            <div className="bg-slate-900 rounded-3xl p-8 text-white">
              <div className="flex items-center justify-between mb-6">
                <div className="flex items-center space-x-2">
                  <Wallet size={20} className="text-emerald-400" />
                  <span className="text-sm font-medium text-slate-400">Wallet Balance</span>
                </div>
                <span className="font-bold">Rs {user.walletBalance.toLocaleString()}</span>
              </div>

              {!canAfford && (
                <div className="flex items-start space-x-3 p-4 bg-red-500/10 rounded-2xl mb-6">
                  <AlertCircle size={20} className="text-red-400 flex-shrink-0" />
                  <div className="text-xs">
                    <p className="font-bold text-red-400">Insufficient Balance</p>
                    <Link to="/wallet" className="text-white underline mt-1 block">Deposit Now</Link>
                  </div>
                </div>
              )}

              <button
                onClick={handlePurchase}
                disabled={selectedTokens.length === 0 || !canAfford || showSuccess}
                className={`w-full py-4 rounded-2xl font-bold text-center transition-all flex items-center justify-center space-x-2 ${
                  selectedTokens.length === 0 || !canAfford
                    ? 'bg-slate-700 text-slate-500 cursor-not-allowed'
                    : 'bg-indigo-600 hover:bg-indigo-500 text-white'
                }`}
              >
                {showSuccess ? (
                  <>
                    <CheckCircle2 size={20} />
                    <span>Purchase Successful!</span>
                  </>
                ) : (
                  <span>Confirm Purchase</span>
                )}
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default TokenPurchasePage;

import React, { useState, useEffect } from 'react';
import { Trophy, Timer, Star, CheckCircle } from 'lucide-react';

const WinnersPage: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'SILVER' | 'GOLD' | 'PLATINUM'>('SILVER');
  const [isDrawing, setIsDrawing] = useState(false);
  const [drawProgress, setDrawProgress] = useState(0);
  const [winners, setWinners] = useState<number[]>([]);

  // Simulate a live draw
  const startDraw = () => {
    setIsDrawing(true);
    setDrawProgress(0);
    setWinners([]);

    let p = 0;
    const interval = setInterval(() => {
      p += 1;
      setDrawProgress(p);

      if (p % 10 === 0 && winners.length < 10) {
        setWinners(prev => [...prev, Math.floor(Math.random() * 200) + 1]);
      }

      if (p >= 100) {
        clearInterval(interval);
        setTimeout(() => setIsDrawing(false), 2000);
      }
    }, 50);
  };

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
      <div className="text-center mb-16">
        <h1 className="text-4xl font-extrabold text-slate-900 mb-4">Lottery Winners</h1>
        <p className="text-slate-600 text-lg italic">"Aapki qismat bhi yahan khul sakti hai!"</p>
      </div>

      {/* Tabs */}
      <div className="flex flex-wrap justify-center gap-4 mb-12">
        {['SILVER', 'GOLD', 'PLATINUM'].map((tab) => (
          <button
            key={tab}
            onClick={() => setActiveTab(tab as any)}
            className={`px-8 py-3 rounded-2xl font-bold transition-all shadow-sm ${
              activeTab === tab 
                ? 'bg-indigo-600 text-white shadow-indigo-200' 
                : 'bg-white text-slate-600 hover:bg-slate-50'
            }`}
          >
            {tab} Winners
          </button>
        ))}
      </div>

      {/* Live Draw Simulator (For Demo) */}
      {!isDrawing && winners.length === 0 && (
        <div className="bg-gradient-to-br from-indigo-900 to-slate-900 rounded-[40px] p-12 text-center text-white relative overflow-hidden mb-12">
           <div className="absolute top-0 left-0 w-full h-full opacity-10 bg-[url('https://www.transparenttextures.com/patterns/cubes.png')]"></div>
           <div className="relative z-10 max-w-2xl mx-auto">
             <div className="flex justify-center mb-8">
               <div className="w-24 h-24 bg-indigo-500/20 rounded-full flex items-center justify-center animate-pulse">
                 <Timer size={48} className="text-indigo-400" />
               </div>
             </div>
             <h2 className="text-3xl font-bold mb-4">Next Draw Starts Soon!</h2>
             <p className="text-indigo-200 mb-10 leading-relaxed text-lg">
               Draw hone mein sirf kuch hi ghantay bache hain! Apne tokens check karein aur best of luck!
             </p>
             <div className="grid grid-cols-3 gap-6 mb-12">
                <div className="bg-white/10 backdrop-blur rounded-3xl p-6">
                  <span className="block text-3xl font-bold">14</span>
                  <span className="text-xs uppercase text-indigo-300 font-bold">Hours</span>
                </div>
                <div className="bg-white/10 backdrop-blur rounded-3xl p-6">
