        </div>
      </div>

      {/* Deposit Modal */}
      {showDeposit && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
           <div className="bg-white w-full max-w-md rounded-[40px] overflow-hidden animate-in zoom-in duration-300">
             <div className="p-8 border-b border-slate-50 flex justify-between items-center">
               <h3 className="text-xl font-bold">Deposit Money</h3>
               <button onClick={() => setShowDeposit(false)} className="text-slate-400 hover:text-slate-600">
                 <X size={24} />
               </button>
             </div>
             <form onSubmit={handleDeposit} className="p-8 space-y-6">
                <div className="flex space-x-4">
                  {['EasyPaisa', 'JazzCash'].map((m) => (
                    <button
                      key={m}
                      type="button"
                      onClick={() => setMethod(m as any)}
                      className={`flex-1 py-3 rounded-2xl border-2 font-bold transition-all ${
                        method === m ? 'border-indigo-600 bg-indigo-50 text-indigo-600' : 'border-slate-100 text-slate-400'
