import { Wallet, History, Filter, AlertCircle, X, Plus, Minus, CreditCard, ArrowUpRight, ArrowDownLeft, Clock, CheckCircle2, XCircle } from 'lucide-react';
import { Transaction } from '../types';

const WalletPage: React.FC = () => {
  const { user, transactions, addTransaction, updateBalance } = useUser();
  const [showDeposit, setShowDeposit] = useState(false);
  const [showWithdraw, setShowWithdraw] = useState(false);
  const [method, setMethod] = useState<'EasyPaisa' | 'JazzCash'>('EasyPaisa');
  const [amount, setAmount] = useState('');
  const [txId, setTxId] = useState('');
  const [accNum, setAccNum] = useState('');
  const [accName, setAccName] = useState('');

  // Lock body scroll when modals are open
  useEffect(() => {
    if (showDeposit || showWithdraw) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = 'unset';
    }
    return () => { document.body.style.overflow = 'unset'; };
  }, [showDeposit, showWithdraw]);

  const processingFee = amount ? parseFloat(amount) * 0.1 : 0;
  const receiveAmount = amount ? parseFloat(amount) - processingFee : 0;

  const handleDeposit = (e: React.FormEvent) => {
    e.preventDefault();
    const newTx: Transaction = {
      id: 'tx_' + Math.random(),
      date: new Date().toLocaleString(),
      type: 'DEPOSIT',
      amount: parseFloat(amount),
      charges: processingFee,
      netAmount: receiveAmount,
      status: 'PENDING',
      method
    };
    addTransaction(newTx);
    setShowDeposit(false);
    setAmount('');
    setTxId('');
    alert("Payment submitted! Waiting for admin approval.");
  };

  const handleWithdraw = (e: React.FormEvent) => {
    e.preventDefault();
    const val = parseFloat(amount);
    if (val > user.walletBalance) return alert("Insufficient balance");

    const newTx: Transaction = {
      id: 'tx_' + Math.random(),
      date: new Date().toLocaleString(),
      type: 'WITHDRAWAL',
      amount: val,
      charges: processingFee,
      netAmount: receiveAmount,
      status: 'PENDING',
      method
    };
    addTransaction(newTx);
    updateBalance(-val);
    setShowWithdraw(false);
    setAmount('');
    setAccNum('');
    setAccName('');
    alert("Withdrawal request submitted!");
  };

  return (
    <div className="min-h-screen bg-[#f8fafc] pb-20">
