        <Routes>
          {/* User Routes */}
          <Route path="/" element={isLoggedIn ? <HomePage /> : <Navigate to="/login" />} />
          <Route path="/login" element={!isLoggedIn ? <LoginPage /> : <Navigate to="/" />} />
